import{_ as a,o as e,c as o,ai as r}from"./chunks/framework.DMjte4z8.js";const p=JSON.parse('{"title":"触发器系统概述","description":"","frontmatter":{"title":"触发器系统概述","category":"triggers","updated":"2026-05-07T00:00:00.000Z","model":"minimax/MiniMax-M2.7-highspeed","quality_score":0.7,"discovered_via":"manual"},"headers":[],"relativePath":"triggers/触发器系统概述.md","filePath":"triggers/触发器系统概述.md","lastUpdated":1779351155000}'),i={name:"triggers/触发器系统概述.md"};function s(n,t,l,d,u,_){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="触发器系统概述" tabindex="-1">触发器系统概述 <a class="header-anchor" href="#触发器系统概述" aria-label="Permalink to “触发器系统概述”">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to “概述”">​</a></h2><p>触发器系统是魔兽地图编辑器的&quot;大脑&quot;——它决定了游戏中的<strong>一切事件</strong>该如何响应。比如当一个单位死亡时显示什么信息，当玩家建造建筑时扣除多少资源，当游戏开始时显示什么提示……这些都需要触发器来完成。</p><p>简单来说，<strong>触发器 = 事件 + 条件 + 动作</strong>。当某个&quot;事件&quot;发生时，系统会检查&quot;条件&quot;是否满足，如果满足就执行预设的&quot;动作&quot;。比如：&quot;当单位死亡（事件）→ 如果是英雄（条件）→ 显示失败画面（动作）&quot;。</p><h3 id="为什么必须学习触发器" tabindex="-1">为什么必须学习触发器？ <a class="header-anchor" href="#为什么必须学习触发器" aria-label="Permalink to “为什么必须学习触发器？”">​</a></h3><p>如果你只是摆放地图地形和单位，地图会像一个没有规则的沙盒——单位不会移动，技能不会生效，建筑不会产出资源。<strong>触发器让地图&quot;活&quot;起来</strong>，是制作RPG、PVP、TD等各类地图必不可少的功能。</p><h3 id="学习目标" tabindex="-1">学习目标 <a class="header-anchor" href="#学习目标" aria-label="Permalink to “学习目标”">​</a></h3><p>学完本节后，你将：</p><ul><li>理解触发器的基本结构和三大组成部分</li><li>能够在触发器编辑器中创建第一个触发器</li><li>理解什么是事件、条件和动作</li></ul><blockquote><p><strong>💡 新手提示</strong>：不要被&quot;触发器&quot;这个名字吓到！它本质上是&quot;如果…那么…&quot;的逻辑。你每天都在做这样的判断，只是现在要用电脑语言来表达而已。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手常常跳过触发器编辑器，只做地形和单位装饰，然后奇怪为什么地图玩不起来。记住——<strong>不写触发器的地图只是静态画面，不是游戏</strong>。</p></blockquote>',11)])])}const h=a(i,[["render",s]]);export{p as __pageData,h as default};
